parameters.query:
DECLARE @MAVATTU NVARCHAR(50) = '{{ $json.output.MAVATTU }}';
DECLARE @MOTA NVARCHAR(255) = '{{ $json.output.MOTA }}';
DECLARE @MAKHO NVARCHAR(50) = '{{ $json.output.MAKHO }}';
DECLARE @TENKHO NVARCHAR(255) = '{{ $json.output.TENKHO }}';
DECLARE @MVT NVARCHAR(50);

-- lấy mã vật tư
SELECT TOP 1
    @MVT = PAR_CODE
FROM R5PARTS
WHERE
    (@MAVATTU <> '' AND PAR_CODE = @MAVATTU)
    OR
    (@MOTA <> '' AND PAR_DESC LIKE '%' + @MOTA + '%');

-- thông tin vật tư
SELECT
    PAR_CODE AS MAVATTU,
    PAR_DESC AS TENVATTU
FROM R5PARTS
WHERE PAR_CODE = @MVT;

-- tồn kho theo kho
SELECT
    STO_STORE AS KHO,
    STO_QTY AS SOLUONGTON
FROM R5STOCK
WHERE 
    STO_PART = @MVT
    AND STO_QTY IS NOT NULL
    AND (
        (@MAKHO <> '' AND STO_STORE = @MAKHO)
        OR
        (@MAKHO = '' )
    )
ORDER BY STO_STORE;

