parameters.query:
DECLARE @startdate DATE = '{{ $json.output.startdate }}';
DECLARE @enddate   DATE = '{{ $json.output.enddate }}';

SELECT COUNT(*) AS TONGSO
FROM R5TRANSLINES
WHERE TRL_DATE >= @startdate
AND TRL_DATE < DATEADD(day, 1, @enddate);

SELECT TOP 3 TRL_PART
FROM R5TRANSLINES
WHERE TRL_DATE >= @startdate
AND TRL_DATE < DATEADD(day, 1, @enddate)
ORDER BY TRL_DATE DESC;

